// Compute the geometry and timing of a route from an ordered list of points.
// Pure function: no network or closure dependencies, so it is directly unit-testable.
//
// points: [{ lat, lon }, ...] in visiting order (index 0 is the origin/boat).
// speedKnots: constant boat speed in knots (nm/hour).
// startTimeMs: departure time of the first leg, in UTC milliseconds.
//
// Returns null when there are fewer than 2 points or a non-positive speed.
// Otherwise returns { legs, totals } where each leg carries distance (nm),
// initial great-circle bearing (deg + 16-point compass), duration (hours), and
// cumulative depart/arrive times (UTC ms). totals aggregates the whole route.
function computeRoutePlan(points: any[], speedKnots: number, startTimeMs: number) {
  // Guards: need at least one leg and a usable speed
  if (!Array.isArray(points) || points.length < 2) return null;
  if (typeof speedKnots !== 'number' || !isFinite(speedKnots) || speedKnots <= 0) return null;

  // Earth radius in nautical miles — keeps distances in marine units directly
  const EARTH_RADIUS_NM = 3440.065;
  const toRad = (deg: number) => deg * Math.PI / 180;
  const toDeg = (rad: number) => rad * 180 / Math.PI;
  const round1 = (n: number) => Math.round(n * 10) / 10;

  // 16-point compass label from a bearing in degrees
  const compass = (deg: number) => {
    const dirs = ['N','NNE','NE','ENE','E','ESE','SE','SSE','S','SSW','SW','WSW','W','WNW','NW','NNW'];
    return dirs[Math.round(((deg % 360) + 360) % 360 / 22.5) % 16];
  };

  // Great-circle (haversine) distance between two lat/lon points, in nautical miles
  const haversineNm = (a: any, b: any) => {
    const dLat = toRad(b.lat - a.lat);
    const dLon = toRad(b.lon - a.lon);
    const lat1 = toRad(a.lat);
    const lat2 = toRad(b.lat);
    const h = Math.sin(dLat / 2) * Math.sin(dLat / 2)
      + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
    return 2 * EARTH_RADIUS_NM * Math.asin(Math.min(1, Math.sqrt(h)));
  };

  // Initial bearing (forward azimuth) from a to b, normalized to 0..360
  const initialBearing = (a: any, b: any) => {
    const lat1 = toRad(a.lat);
    const lat2 = toRad(b.lat);
    const dLon = toRad(b.lon - a.lon);
    const y = Math.sin(dLon) * Math.cos(lat2);
    const x = Math.cos(lat1) * Math.sin(lat2) - Math.sin(lat1) * Math.cos(lat2) * Math.cos(dLon);
    return (toDeg(Math.atan2(y, x)) + 360) % 360;
  };

  // Resolve a usable start time — default to "now" if not a finite number
  const start = (typeof startTimeMs === 'number' && isFinite(startTimeMs)) ? startTimeMs : Date.now();

  // Build each leg, accumulating distance/time as we walk the route
  const legs: any[] = [];
  let cumulativeDistanceNm = 0;
  let cumulativeHours = 0;

  for (let i = 0; i < points.length - 1; i++) {
    const from = points[i];
    const to = points[i + 1];

    const distanceNm = haversineNm(from, to);
    const bearing = initialBearing(from, to);
    const durationHours = distanceNm / speedKnots;

    // Depart at the running cumulative offset; arrive after this leg's duration
    const departTimeMs = start + cumulativeHours * 3600000;
    const arriveTimeMs = departTimeMs + durationHours * 3600000;

    legs.push({
      index: i,
      from: { lat: from.lat, lon: from.lon },
      to: { lat: to.lat, lon: to.lon },
      distanceNm: round1(distanceNm),
      bearing: Math.round(bearing),
      bearingCompass: compass(bearing),
      durationHours: Math.round(durationHours * 100) / 100,
      departTimeMs: Math.round(departTimeMs),
      arriveTimeMs: Math.round(arriveTimeMs)
    });

    cumulativeDistanceNm += distanceNm;
    cumulativeHours += durationHours;
  }

  // Whole-route totals — ETA is the arrival of the final leg
  const totals = {
    distanceNm: round1(cumulativeDistanceNm),
    durationHours: Math.round(cumulativeHours * 100) / 100,
    departTimeMs: Math.round(start),
    etaMs: Math.round(start + cumulativeHours * 3600000)
  };

  return { legs, totals };
}
